      <p className="text-[13px] text-[#525252] mt-0.5">{description}</p>
    </div>
  );
}

function ProjectLink({ name, href }: { name: string; href: string }) {
  return (
    <a
      href={href}
      className="group flex items-center gap-2 text-[15px] text-[#a3a3a3] hover:text-white transition-colors"
    >
      <span className="text-[#525252] group-hover:text-[#737373] transition-colors">
        ·
      </span>
      <span className="border-b border-dotted border-[#525252] group-hover:border-[#a3a3a3] transition-colors">
        {name}
      </span>
      <span className="text-[12px] text-[#525252] font-mono">↗</span>
    </a>
  );
}

function Tag({ children }: { children: React.ReactNode }) {
  return (
    <span className="px-2 py-0.5 text-[12px] text-[#737373] border border-[#2a2a2a] rounded">
      {children}
    </span>
  );
}

